from lxml import etree
import io

def process_soap_request(xml_content):
    # Enable DTD validation
    parser = etree.XMLParser(dtd_validation=True, load_dtd=True, no_network=False)
    
    try:
        # Parse the XML with DTD validation
        soap_doc = etree.parse(io.BytesIO(xml_content.encode('utf-8')), parser)
        
        # Extract SOAP envelope and body
        soap_envelope = soap_doc.getroot()
        
        # Find the SOAP body
        body = soap_envelope.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
        
        if body is not None:
            # Extract message content from body
            message_content = []
            for child in body:
                message_content.append(etree.tostring(child, encoding='unicode', method='xml'))
            
            return {
                'envelope': etree.tostring(soap_envelope, encoding='unicode', method='xml'),
                'body': body,
                'message_content': message_content
            }
        else:
            raise ValueError("SOAP Body not found in request")
            
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid SOAP request: {str(e)}")